mapper.update:
UPDATE gb_workflow_execution
status = #{status}, output_data = #{outputData}, error = #{error}, end_time = #{endTime}, duration = #{duration},
WHERE execution_id = #{executionId}

mapper.select:
SELECT e.id, e.execution_id, e.workflow_code,
       w.workflow_name AS workflow_name,
       e.mode, e.status,
       e.input_data, e.output_data, e.error,
       e.start_time, e.end_time, e.duration,
       e.site_id, e.create_by, e.create_time
FROM gb_workflow_execution e
LEFT JOIN gb_workflow w ON w.workflow_code = e.workflow_code


        AND e.workflow_code = #{workflowCode}


        AND e.status = #{status}


        AND e.mode = #{mode}


        AND e.site_id = #{siteId}


        AND e.create_time >= #{beginTime}


        AND e.create_time <= #{endTimeStr}


ORDER BY e.create_time DESC

SELECT workflow_code AS workflowCode, COUNT(*) AS totalCount, SUM(CASE WHEN status = 'success' THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN status = 'failed' THEN 1 ELSE 0 END) AS failedCount, AVG(CASE WHEN status = 'success' AND duration IS NOT NULL THEN duration END) AS avgDuration, MAX(create_time) AS lastRunTime FROM gb_workflow_execution WHERE workflow_code IN
#{code}
GROUP BY workflow_code

mapper.delete:
DELETE FROM gb_workflow_execution
WHERE workflow_code = #{workflowCode}
  AND id NOT IN (
      SELECT id FROM (
          SELECT id FROM gb_workflow_execution
          WHERE workflow_code = #{workflowCode}
          ORDER BY create_time DESC
          LIMIT #{keepCount}
      ) t
  )
